INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-00861', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「場域論」的敘述，下列何者正確？①場域論是社會心理學的主要理論之一，起源於十九世', '["生活空間是場域論的基本結構，是指吾人所經驗的主觀和客觀的環境", "場 域論可幫助團體工作者理解，經營或改變團體的社會情境，可作為改變個人行為的一部分，或是 帶來個人行為改變的可能性", "尚未被滿足但已升起的心理需求創造了一種未解決的緊張體系。 當任務完成後，相關的緊張體系即消散", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00862', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '系統理論在不同觀點所衍生出的概念，特別與團體工作者有關的部分，下列何者錯誤？', '["團體被視為一個整體的特質，主要是源自於個別成員之間的互動", "團體成員在團體中所表現出來的行為，是源自於早期生活經驗未被解決的衝突", "當面對衝突時，團體會努力維持自己成為一個獨立存在的實體", "團體經常處在形成、發展及改變的狀態，這些重複出現的情況會影響團體的平衡及繼續存在"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00863', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作者使用比喻的技巧，下列何者錯誤？①比喻是團體成員使用象徵性的語言來描述其', '["比喻由團體工作者提出，團體成員很難使用比喻", "比喻可 以提供引導團體成員注意的方法，從以現在為中心轉移到以過去為焦點", "團體工作者可以使用 比喻來核對團體發展的階段", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00864', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體發展的敘述，下列何者錯誤？', '["團體發展亦可說是團體的生命循環", "大多數團體的移動還是可以看出不同的階段發展", "團體發展階段是由團體內部系統與外部環境的互動關係所開展出來的", "任何團體的移動是隨著一個有秩序的步調，而團體成長卻處在一種前進與後退均不規律的階段"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00865', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體聚會的次數和聚會時間的敘述，下列何者錯誤？', '["若團體結束前5分鐘出現危機議題，團體領導者仍應依照時間架構的規劃結束團體", "聚會時間長度少於1小時通常無法有足夠的時間能周全地討論所提出的問題；而聚會時間超過 3小時，成員亦會變得較無精打采、挫折及無法專注", "團體領導者不需讓團體依序經歷不同階段，因團體會自然的發展，逐漸地達到團體結束", "許多團體會持續數周聚會時間，在每次聚會之間會有若干天的間距，作為團體成員完成個人和 團體目標的指定作業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00866', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關團體領導技巧的敘述，何者正確？①有效面質可以增進團體深入互動  ②團體成員每次', '["為降低團體的分離焦慮， 團體領導者不適宜在團體中分享自己對團體結束的不捨", "當團體成員哭泣時，團體領導者要積 極處理，讓成員感受到支持與同理", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00867', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關團體衝突的處理，何者正確？①當團體發生衝突時，領導者要立即介入，以示範面對衝', '["團體出現衝突時，以緩和技巧為主，避免再出現相互指責或批評", "使用重 新建構及再界定技巧可協助成員從新的觀點來檢視問題", "當團體發生衝突時，領導者是否要立 即介入，應考量團體當下的目標而定", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00868', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作實施倫理的範圍，下列何者錯誤？', '["團體工作者必須具備足夠的團體工作能力", "團體工作實施需要符合機構的宗旨與精神", "團體工作經費的籌募需要依程序辦理", "團體工作實施要以服務對象的需求為優先考量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00869', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者為團體工作實施倫理保密原則之例外？①在團體中有成員揭露危及個人生命安全的訊', '["轉介團體成員至其他機構或服務方案時，提供所需的團 體工作資訊", "因教育訓練需要，新進社工人員不需登記或簽署保密同意，即可參閱團體工作紀 錄", "實習生不需經過機構同意，可以將自己撰寫的團體工作紀錄提供給學校督導", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00870', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作實施過程的倫理兩難議題，下列何者正確？①為確保團體工作的專業品質，由具備', '["因機構 督導的團體工作專業能力有限，未能提供團體工作者合適的督導，屬於機構的倫理兩難", "團體 成員因個人因素退出團體，於團體中期又想再次加入團體，造成團體工作者的倫理兩難", "法院 強制的非自願性成員，堅持要退出團體，造成團體工作者的倫理兩難", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
